{
  "global": "Navigate to the fashion site, locate a baby one piece product, and add one unit of it to the shopping cart.",
  "subtasks": [
    {
      "subtask": "Navigate to the baby or infant clothing section",
      "atomics": [
        "Locate and click the main navigation menu or search bar on the homepage",
        "Select or search for the 'Baby' or 'Kids' category",
        "Apply a filter or browse to the 'One Piece' or 'Bodysuits' sub-category"
      ]
    },
    {
      "subtask": "Select a baby one piece product",
      "atomics": [
        "Scan the product listing page for a baby one piece item",
        "Click on the product thumbnail or title to open the product detail page"
      ]
    },
    {
      "subtask": "Configure and add the product to cart",
      "atomics": [
        "Select a required size or variant if prompted (e.g., 0-3M)",
        "Verify the quantity field is set to 1",
        "Click the 'Add to Cart' button"
      ]
    },
    {
      "subtask": "Confirm the item was added to the cart",
      "atomics": [
        "Observe the cart icon or confirmation message indicating 1 item added",
        "Optionally navigate to the cart page and verify the baby one piece appears with quantity 1"
      ]
    }
  ],
  "global_atomics": [
    "Verify no error dialogs or out-of-stock messages appeared during the add-to-cart flow"
  ],
  "gold_actions": {
    "global": "Click through site navigation to a baby one piece product page, set quantity to 1, and submit the Add to Cart action.",
    "subtasks": [
      {
        "subtask": "Navigate to the baby or infant clothing section",
        "atomics": [
          "Click the top navigation element labeled 'Baby', 'Kids', or use the search input to type 'baby one piece'",
          "Click the 'Baby' category link in the dropdown or search results",
          "Click the 'One Piece' or 'Bodysuits' filter chip or left-rail category link"
        ]
      },
      {
        "subtask": "Select a baby one piece product",
        "atomics": [
          "Identify the first visible baby one piece product card on the listing page",
          "Click the product card image or title link to open the product detail page"
        ]
      },
      {
        "subtask": "Configure and add the product to cart",
        "atomics": [
          "Click a size swatch (e.g., '0-3M') to satisfy the required size selection",
          "Confirm the quantity input reads '1' (edit if necessary)",
          "Click the button labeled 'Add to Cart' or 'Add to Bag'"
        ]
      },
      {
        "subtask": "Confirm the item was added to the cart",
        "atomics": [
          "Read the cart badge or slide-in panel confirming '1 item' or 'Baby One Piece added'",
          "Click the cart icon and assert the baby one piece line item is present with quantity 1"
        ]
      }
    ],
    "global_atomics": [
      "Assert no modal error, size-required warning, or out-of-stock banner is visible after clicking Add to Cart"
    ]
  }
}
